Code Good:
use std::sync::Mutex;

struct Transfer {
    accounts: Vec<Mutex<Account>>,
}

impl Transfer {
    fn transfer(&self, from: usize, to: usize, amount: f64) {
        // Always lock lower index first to prevent deadlock
        let (first, second) = if from < to { (from, to) } else { (to, from) };
        let mut a = self.accounts[first].lock().unwrap();
        let mut b = self.accounts[second].lock().unwrap();
        if from < to {
            a.balance -= amount;
            b.balance += amount;
        } else {
            b.balance -= amount;
            a.balance += amount;
        }
    }
}

