use async_stream::stream;
use tokio_stream::StreamExt;

fn page_results(client: &Client) -> impl Stream<Item = Vec<Record>> + '_ {
    stream! {
        let mut page = 1;
        loop {
            let records = client.fetch_page(page).await;
            if records.is_empty() { break; }
            yield records;
            page += 1;
        }
    }
}

