Code Good:
struct CounterHandle {
    tx: mpsc::Sender<CounterMsg>,
}

enum CounterMsg {
    Increment,
    Get(oneshot::Sender<u64>),
}

impl CounterHandle {
    fn new() -> Self {
        let (tx, mut rx) = mpsc::channel(32);
        tokio::spawn(async move {
            let mut count: u64 = 0;
            while let Some(msg) = rx.recv().await {
                match msg {
                    CounterMsg::Increment => count += 1,
                    CounterMsg::Get(reply) => { let _ = reply.send(count); }
                }
            }
        });
        Self { tx }
    }
    async fn increment(&self) { self.tx.send(CounterMsg::Increment).await.unwrap(); }
    async fn get(&self) -> u64 {
        let (tx, rx) = oneshot::channel();
        self.tx.send(CounterMsg::Get(tx)).await.unwrap();
        rx.await.unwrap()
    }
}

