use std::sync::atomic::{AtomicU64, Ordering};

struct Metrics {
    requests: AtomicU64,
    errors: AtomicU64,
}

impl Metrics {
    fn new() -> Self {
        Self {
            requests: AtomicU64::new(0),
            errors: AtomicU64::new(0),
        }
    }
    fn record_request(&self) { self.requests.fetch_add(1, Ordering::Relaxed); }
    fn record_error(&self) { self.errors.fetch_add(1, Ordering::Relaxed); }
    fn snapshot(&self) -> (u64, u64) {
        (self.requests.load(Ordering::Relaxed), self.errors.load(Ordering::Relaxed))
    }
}

