struct DbPool {
    pool: sqlx::PgPool,
}

impl Drop for DbPool {
    fn drop(&mut self) {
        // Cannot .await in Drop!
        // This panics inside a Tokio runtime:
        tokio::runtime::Handle::current().block_on(async {
            self.pool.close().await;
        });
    }
}
